#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    cin>>n;
    long long z,y,k;
    string x;
    for(int i=0;i<n;i++){
        cin>>z>>x;
        y=1;
        k=0;
        for(int j=x.length()-1;j>=0;j--){
        	if('0'<=x[j]&&x[j]<='9'){
				k+=(x[j]-'0')*y;
			}
			else{
				k+=(x[j]-'A'+10)*y;
			}
			y=y*z;
		}
        cout<<k<<endl;
    }
    return 0;
}
